mapper.select:
WITH RECURSIVE sub AS ( SELECT id, user_id, file_id, parent_id, file_name, is_dir, file_size, status, deleted_at, created_at, updated_at FROM user_file WHERE id = #{rootId} AND user_id = #{userId} UNION ALL SELECT c.id, c.user_id, c.file_id, c.parent_id, c.file_name, c.is_dir, c.file_size, c.status, c.deleted_at, c.created_at, c.updated_at FROM user_file c INNER JOIN sub s ON c.parent_id = s.id WHERE c.user_id = #{userId}
AND c.status = #{status}
) SELECT id, user_id, file_id, parent_id, file_name, is_dir, file_size, status, deleted_at, created_at, updated_at FROM sub LIMIT #{limit}
